import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { describe, expect, it } from "vitest";
import {
  Drawer,
  DrawerClose,
  DrawerContent,
  DrawerDescription,
  DrawerTitle,
  DrawerTrigger,
} from "./Drawer";

function DrawerExample() {
  return (
    <Drawer>
      <DrawerTrigger>Open drawer</DrawerTrigger>
      <DrawerContent>
        <DrawerTitle>Navigation</DrawerTitle>
        <DrawerDescription>Choose a destination.</DrawerDescription>
        <button type="button">First link</button>
        <DrawerClose>Close panel</DrawerClose>
      </DrawerContent>
    </Drawer>
  );
}

function CustomSlotIdDrawerExample() {
  return (
    <Drawer>
      <DrawerTrigger>Open custom drawer</DrawerTrigger>
      <DrawerContent>
        <DrawerTitle id="custom-drawer-title">Custom drawer</DrawerTitle>
        <DrawerDescription id="custom-drawer-description">
          Custom drawer description.
        </DrawerDescription>
        <DrawerClose>Close custom drawer</DrawerClose>
      </DrawerContent>
    </Drawer>
  );
}

describe("Drawer", () => {
  it("opens as a labelled modal, traps focus, and returns focus on Escape", async () => {
    const user = userEvent.setup();

    render(<DrawerExample />);

    const trigger = screen.getByRole("button", { name: "Open drawer" });
    await user.click(trigger);

    const drawer = await screen.findByRole("dialog", {
      name: "Navigation",
    });

    expect(drawer).toHaveAttribute("aria-modal", "true");
    expect(drawer).toHaveAccessibleDescription("Choose a destination.");

    await waitFor(() => {
      expect(screen.getByRole("button", { name: "First link" })).toHaveFocus();
    });

    await user.tab({ shift: true });
    expect(screen.getByRole("button", { name: "Close panel" })).toHaveFocus();

    await user.keyboard("{Escape}");
    expect(screen.queryByRole("dialog")).not.toBeInTheDocument();
    expect(trigger).toHaveFocus();
  });

  it("uses custom title and description ids from slots", async () => {
    const user = userEvent.setup();

    render(<CustomSlotIdDrawerExample />);

    await user.click(screen.getByRole("button", { name: "Open custom drawer" }));

    const drawer = await screen.findByRole("dialog", {
      name: "Custom drawer",
    });

    expect(drawer).toHaveAttribute("aria-labelledby", "custom-drawer-title");
    expect(drawer).toHaveAttribute(
      "aria-describedby",
      "custom-drawer-description",
    );
    expect(drawer).toHaveAccessibleDescription("Custom drawer description.");
  });
});

"use client";

export { Drawer } from "./DrawerContext";
export type { DrawerProps } from "./DrawerContext";
export { DrawerClose } from "./DrawerClose";
export type { DrawerCloseProps } from "./DrawerClose";
export { DrawerContent } from "./DrawerContent";
export type { DrawerContentProps } from "./DrawerContent";
export { DrawerDescription, DrawerHeader, DrawerTitle } from "./DrawerSections";
export type {
  DrawerDescriptionProps,
  DrawerHeaderProps,
  DrawerTitleProps,
} from "./DrawerSections";
export { DrawerTrigger } from "./DrawerTrigger";
export type { DrawerTriggerProps } from "./DrawerTrigger";
export type { DrawerSize, DrawerTone, DrawerVariant } from "./drawer-types";

"use client";

import type { ButtonHTMLAttributes } from "react";
import { forwardRef } from "react";
import {
  Slot,
  cn,
  disabledInteractiveStyles,
  focusVisibleStyles,
  swirskiAttrs,
} from "../../system";
import { useDrawer } from "./DrawerContext";
import type { DrawerSize, DrawerTone, DrawerVariant } from "./drawer-types";
import { drawerButtonSizeStyles } from "./drawer-utils";

export type DrawerCloseProps = ButtonHTMLAttributes<HTMLButtonElement> & {
  asChild?: boolean;
  variant?: DrawerVariant;
  size?: DrawerSize;
  tone?: DrawerTone;
};

export const DrawerClose = forwardRef<HTMLButtonElement, DrawerCloseProps>(
  function DrawerClose(
    {
      asChild = false,
      className,
      children = "Close",
      variant = "default",
      size = "md",
      tone = "default",
      onClick,
      ...props
    },
    ref,
  ) {
    const { setOpen } = useDrawer();
    const Component = asChild ? Slot : "button";

    return (
      <Component
        ref={ref}
        className={cn(
          "mt-6 border-[length:var(--sw-border-width)] border-[color:var(--sw-color-ink)] bg-[var(--sw-color-surface)] font-black uppercase shadow-[4px_4px_0_var(--sw-color-shadow)] outline-none transition-all duration-150 hover:translate-x-1 hover:translate-y-1 hover:shadow-none active:translate-x-2 active:translate-y-2 disabled:hover:shadow-[4px_4px_0_var(--sw-color-shadow)]",
          focusVisibleStyles,
          disabledInteractiveStyles,
          drawerButtonSizeStyles[size],
          className,
        )}
        onClick={(event) => {
          onClick?.(event);

          if (!event.defaultPrevented) {
            setOpen(false);
          }
        }}
        type={asChild ? undefined : "button"}
        {...swirskiAttrs("drawer-close", { size, tone, variant })}
        {...props}
      >
        {children}
      </Component>
    );
  },
);

DrawerClose.displayName = "DrawerClose";

"use client";

import type { HTMLAttributes } from "react";
import { forwardRef, useRef } from "react";
import { createPortal } from "react-dom";
import { cn, composeRefs, swirskiAttrs } from "../../system";
import { useModalOverlay } from "../../system/overlay";
import { usePortalRoot } from "../../hooks/use-portal-root/usePortalRoot";
import { useDrawer } from "./DrawerContext";
import type {
  DrawerSide,
  DrawerSize,
  DrawerTone,
  DrawerVariant,
} from "./drawer-types";
import { drawerSideStyles } from "./drawer-utils";

export type DrawerContentProps = HTMLAttributes<HTMLDivElement> & {
  side?: DrawerSide;
  variant?: DrawerVariant;
  size?: DrawerSize;
  tone?: DrawerTone;
};

export const DrawerContent = forwardRef<HTMLDivElement, DrawerContentProps>(
  function DrawerContent(
    {
      side = "right",
      className,
      children,
      variant = "default",
      size = "md",
      tone = "default",
      ...props
    },
    ref,
  ) {
    const { describedById, labelledById, open, setOpen } = useDrawer();
    const portalRoot = usePortalRoot();
    const contentRef = useRef<HTMLDivElement>(null);

    useModalOverlay({
      contentRef,
      onEscape: () => setOpen(false),
      open,
    });

    if (!open || !portalRoot) {
      return null;
    }

    return createPortal(
      <div className="fixed inset-0 z-50 bg-black/45">
        <button
          aria-label="Close drawer"
          className="absolute inset-0"
          onClick={() => setOpen(false)}
          type="button"
        />
        <div
          ref={composeRefs(contentRef, ref)}
          className={cn(
            "absolute border-4 border-black bg-white p-6 shadow-[12px_12px_0_#0B0B0C]",
            drawerSideStyles[side],
            variant === "compact" && "p-5 shadow-[8px_8px_0_#0B0B0C]",
            className,
          )}
          role="dialog"
          aria-modal="true"
          aria-labelledby={labelledById ?? props["aria-labelledby"]}
          aria-describedby={describedById ?? props["aria-describedby"]}
          tabIndex={-1}
          {...swirskiAttrs("drawer-content", { size, tone, variant })}
          {...props}
        >
          {children}
        </div>
      </div>,
      portalRoot,
    );
  },
);

DrawerContent.displayName = "DrawerContent";

"use client";

import type { ReactNode } from "react";
import { createContext, useCallback, useContext, useId, useState } from "react";
import type { DrawerSize, DrawerTone, DrawerVariant } from "./drawer-types";

type DrawerContextValue = {
  open: boolean;
  setOpen: (open: boolean) => void;
  titleId: string;
  descriptionId: string;
  labelledById?: string;
  describedById?: string;
  setLabelledById: (id: string | undefined) => void;
  setDescribedById: (id: string | undefined) => void;
};

export const DrawerContext = createContext<DrawerContextValue | null>(null);

export type DrawerProps = {
  children: ReactNode;
  open?: boolean;
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean) => void;
  variant?: DrawerVariant;
  size?: DrawerSize;
  tone?: DrawerTone;
};

export function useDrawer() {
  const context = useContext(DrawerContext);

  if (!context) {
    throw new Error("Drawer components must be used inside Drawer.");
  }

  return context;
}

export function Drawer({
  children,
  open,
  defaultOpen = false,
  onOpenChange,
  variant: _variant = "default",
  size: _size = "md",
  tone: _tone = "default",
}: DrawerProps) {
  const titleId = useId();
  const descriptionId = useId();
  const [internalOpen, setInternalOpen] = useState(defaultOpen);
  const [labelledById, setLabelledById] = useState<string | undefined>();
  const [describedById, setDescribedById] = useState<string | undefined>();
  const isControlled = open !== undefined;
  const currentOpen = open ?? internalOpen;

  const setOpen = useCallback((nextOpen: boolean) => {
    if (!isControlled) {
      setInternalOpen(nextOpen);
    }

    onOpenChange?.(nextOpen);
  }, [isControlled, onOpenChange]);

  return (
    <DrawerContext.Provider
      value={{
        open: currentOpen,
        setOpen,
        titleId,
        descriptionId,
        labelledById,
        describedById,
        setLabelledById,
        setDescribedById,
      }}
    >
      {children}
    </DrawerContext.Provider>
  );
}

"use client";

import type { HTMLAttributes } from "react";
import { forwardRef, useEffect } from "react";
import { Slot, cn, swirskiAttrs } from "../../system";
import { useDrawer } from "./DrawerContext";
import type { DrawerSize, DrawerTone, DrawerVariant } from "./drawer-types";

export type DrawerHeaderProps = {
  asChild?: boolean;
  variant?: DrawerVariant;
  size?: DrawerSize;
  tone?: DrawerTone;
} & HTMLAttributes<HTMLDivElement>;

export const DrawerHeader = forwardRef<HTMLDivElement, DrawerHeaderProps>(
  function DrawerHeader(
    {
      asChild = false,
      className,
      variant = "default",
      size = "md",
      tone = "default",
      ...props
    },
    ref,
  ) {
    const Component = asChild ? Slot : "div";

    return (
      <Component
        ref={ref}
        className={cn("grid gap-2", className)}
        {...swirskiAttrs("drawer-header", { size, tone, variant })}
        {...props}
      />
    );
  },
);

DrawerHeader.displayName = "DrawerHeader";

export type DrawerTitleProps = {
  asChild?: boolean;
  variant?: DrawerVariant;
  size?: DrawerSize;
  tone?: DrawerTone;
} & HTMLAttributes<HTMLHeadingElement>;

export const DrawerTitle = forwardRef<HTMLHeadingElement, DrawerTitleProps>(
  function DrawerTitle(
    {
      asChild = false,
      className,
      variant = "default",
      size = "md",
      tone = "default",
      ...props
    },
    ref,
  ) {
    const { setLabelledById, titleId } = useDrawer();
    const Component = asChild ? Slot : "h2";
    const id = props.id ?? titleId;

    useEffect(() => {
      setLabelledById(id);
      return () => setLabelledById(undefined);
    }, [id, setLabelledById]);

    return (
      <Component
        ref={ref}
        className={cn("font-anton text-4xl uppercase leading-none", className)}
        id={id}
        {...swirskiAttrs("drawer-title", { size, tone, variant })}
        {...props}
      />
    );
  },
);

DrawerTitle.displayName = "DrawerTitle";

export type DrawerDescriptionProps = {
  asChild?: boolean;
  variant?: DrawerVariant;
  size?: DrawerSize;
  tone?: DrawerTone;
} & HTMLAttributes<HTMLParagraphElement>;

export const DrawerDescription = forwardRef<
  HTMLParagraphElement,
  DrawerDescriptionProps
>(function DrawerDescription(
  {
    asChild = false,
    className,
    variant = "default",
    size = "md",
    tone = "default",
    ...props
  },
  ref,
) {
  const { descriptionId, setDescribedById } = useDrawer();
  const Component = asChild ? Slot : "p";
  const id = props.id ?? descriptionId;

  useEffect(() => {
    setDescribedById(id);
    return () => setDescribedById(undefined);
  }, [id, setDescribedById]);

  return (
    <Component
      ref={ref}
      className={cn("text-sm font-bold leading-6 text-black/65", className)}
      id={id}
      {...swirskiAttrs("drawer-description", { size, tone, variant })}
      {...props}
    />
  );
});

DrawerDescription.displayName = "DrawerDescription";

"use client";

import type { ButtonHTMLAttributes } from "react";
import { forwardRef } from "react";
import {
  Slot,
  cn,
  disabledInteractiveStyles,
  focusVisibleStyles,
  swirskiAttrs,
} from "../../system";
import { useDrawer } from "./DrawerContext";
import type { DrawerSize, DrawerTone, DrawerVariant } from "./drawer-types";
import { drawerButtonSizeStyles } from "./drawer-utils";

export type DrawerTriggerProps = ButtonHTMLAttributes<HTMLButtonElement> & {
  asChild?: boolean;
  variant?: DrawerVariant;
  size?: DrawerSize;
  tone?: DrawerTone;
};

export const DrawerTrigger = forwardRef<HTMLButtonElement, DrawerTriggerProps>(
  function DrawerTrigger(
    {
      asChild = false,
      className,
      variant = "default",
      size = "md",
      tone = "default",
      onClick,
      ...props
    },
    ref,
  ) {
    const { setOpen } = useDrawer();
    const Component = asChild ? Slot : "button";

    return (
      <Component
        ref={ref}
        className={cn(
          "border-[length:var(--sw-border-width)] border-[color:var(--sw-color-ink)] bg-[var(--sw-color-blue)] font-black uppercase text-white shadow-[5px_5px_0_var(--sw-color-shadow)] outline-none transition-all duration-150 hover:translate-x-1 hover:translate-y-1 hover:shadow-none active:translate-x-2 active:translate-y-2 disabled:hover:shadow-[5px_5px_0_var(--sw-color-shadow)]",
          focusVisibleStyles,
          disabledInteractiveStyles,
          drawerButtonSizeStyles[size],
          variant === "compact" && "shadow-[3px_3px_0_var(--sw-color-shadow)] disabled:hover:shadow-[3px_3px_0_var(--sw-color-shadow)]",
          className,
        )}
        onClick={(event) => {
          onClick?.(event);

          if (!event.defaultPrevented) {
            setOpen(true);
          }
        }}
        type={asChild ? undefined : "button"}
        {...swirskiAttrs("drawer-trigger", { size, tone, variant })}
        {...props}
      />
    );
  },
);

DrawerTrigger.displayName = "DrawerTrigger";

export type DrawerVariant = "default" | "compact";
export type DrawerSize = "sm" | "md" | "lg";
export type DrawerTone = "default";
export type DrawerSide = "left" | "right" | "top" | "bottom";

import type { DrawerSide, DrawerSize } from "./drawer-types";

export const drawerButtonSizeStyles: Record<DrawerSize, string> = {
  sm: "px-4 py-2 text-sm",
  md: "px-5 py-3",
  lg: "px-6 py-4 text-lg",
};

export const drawerSideStyles: Record<DrawerSide, string> = {
  left: "left-0 top-0 h-full w-full max-w-sm",
  right: "right-0 top-0 h-full w-full max-w-sm",
  top: "left-0 top-0 w-full",
  bottom: "bottom-0 left-0 w-full",
};
